 theta_s := ComputeStateDependentThreshold(s_prime)
 phi_val := self.Phi(s_prime, psi_val)

 decision := CostDecision(
 from_state = s,
 to_state = s_prime,
 psi = psi_val,
 phi = phi_val,
 permitted = (phi_val == 1 AND psi_val <= SINPHASE_GOVERNANCE_BOUND)
 )

 self.audit_log.APPEND(decision)
