 END IF
 IF alpha_m < ALPHA_MIN OR alpha_m > ALPHA_MAX:
 EMIT WARNING "α=" + alpha_m + " outside recommended [0.2, 0.4]"
 ok := FALSE
 END IF
 RETURN ok
END PROCEDURE

