DEFINE SECURITY_AS_CODE_PROPERTIES AS:
 versionable:
 // All security configurations tracked in version control
 ALL security_configs STORED_IN version_control_system
 testable:
 // Automated security validation in CI/CD pipelines
 CI_CD_PIPELINE INCLUDES security_scan_stage
