PROCEDURE tucker_decompose(E_tensor, ε_threshold) -> TUCKER_DECOMPOSITION_RESULT:
 // Perform Tucker decomposition
 G, A, B, C, D, F_mat = tucker_decomposition(E_tensor)

 // Reconstruct from decomposition (Equation 4):
 // E' = G ×₁ A ×₂ B ×₃ C ×₄ D ×₅ F
