FUNCTION compute_semantic_salience(
 glyph: Glyph, // G_i
 knowledge_state: KnowledgeState,// K_t
 cultural_ctx: CulturalContext,
 config: CSLConfiguration
) -> Float:

 // Component 1: Bayesian posterior probability
