FUNCTION execute_marshalling_operation(
 D: DistributedSystem,
 s: SystemState,
 op: Operation,
 n_i: NodeID,
 n_j: NodeID,
 Sigma: SignatureScheme
 ) -> MarshallingResult:

 // --- Phase 1: Validate topology and edge existence (Module 1) ---
